+    fn fsck_skips_clean_ext4_scrub_without_force() {
+        const EXT4_VALID_FS: u16 = 0x0001;
+        let image = build_test_ext4_image_with_state(EXT4_VALID_FS);
+        let output = with_temp_image_path(&image, |path| {
