+            .phases
+            .iter()
+            .find(|phase| phase.phase == "checksum_scrub")
+            .expect("checksum_scrub phase should be present");
+        assert_eq!(scrub_phase.status, "skipped");
+        assert!(scrub_phase.detail.contains("pass --force for full scrub"));
